{
  "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
  "contentVersion": "1.0.0.0",
  "parameters": {
    "dashboardName": { "type": "string" },
    "location": { "type": "string", "defaultValue": "[resourceGroup().location]" }
  },
  "resources": [
    {
      "type": "Microsoft.Portal/dashboards",
      "apiVersion": "2020-09-01-preview",
      "name": "[parameters('dashboardName')]",
      "location": "[parameters('location')]",
      "tags": {
        "hidden-title": "Operations Dashboard",
        "Environment": "Production"
      },
      "properties": {
        "lenses": {
          "0": {
            "order": 0,
            "parts": {}
          }
        },
        "metadata": {
          "model": {}
        }
      }
    }
  ]
}

# Deploy a cost monitoring dashboard via ARM
cat << 'EOF' > cost-dashboard.json
{
  "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
  "contentVersion": "1.0.0.0",
  "resources": [
    {
      "type": "Microsoft.Portal/dashboards",
      "apiVersion": "2020-09-01-preview",
      "name": "cost-centre-dashboard",
      "location": "eastus",
      "tags": {
        "hidden-title": "Cost Centre Dashboard",
        "Purpose": "Finance"
      },
      "properties": {
        "lenses": {
          "0": {
            "order": 0,
            "parts": {}
          }
        },
        "metadata": { "model": {} }
      }
    }
  ]
}
EOF

az deployment group create \
  --resource-group rg-shared-ops \
  --template-file cost-dashboard.json

# After deploying, grant Finance team read-only access
DASH_ID=$(az resource show \
  --resource-group rg-shared-ops \
  --resource-type Microsoft.Portal/dashboards \
  --name cost-centre-dashboard --query id -o tsv)

FINANCE_GRP=$(az ad group show --group "finance-viewers" --query id -o tsv)

az role assignment create \
  --role Reader --assignee-object-id "$FINANCE_GRP" \
  --assignee-principal-type Group --scope "$DASH_ID"

echo "Cost dashboard deployed and shared with Finance group"
